:root {
  --color-gray: #656565;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  width: 100%;
  height: 100vh;
  background: url("./hero-4.jpg") no-repeat 50% 50%;
  background-size: cover;
  font-family: "Saans TRIAL";
  overflow: hidden;
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

i {
  font-size: 24px;
  color: var(--color-gray);
}

.search {
  width: 100%;
  margin-top: 7.5em;
}

.search-modal {
  margin: 0 auto;
  width: 40%;
  background: linear-gradient(
    320deg,
    rgba(27, 27, 27, 0.9) 0%,
    rgba(20, 20, 20, 0.96) 100%
  );
  backdrop-filter: blur(20px);
  color: #fff;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 1em;
  overflow: hidden;
}

.search-bar {
  position: relative;
  width: 100%;
  display: flex;
  align-items: center;
  padding: 1em;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.action-icons {
  position: absolute;
  right: 0;
  display: flex;
  gap: 1em;
  padding: 1em;
}

.input {
  width: 80%;
}

#search-input {
  width: 100%;
  background: none;
  outline: none;
  border: none;
  color: #fff;
  font-family: "Saans TRIAL";
  font-size: 15px;
  padding-left: 1em;
}

::placeholder {
  color: var(--color-gray);
}

.tags-container {
  padding: 1em;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.tags-container span {
  color: var(--color-gray);
  font-size: 13.5px;
}

.tags {
  width: 100%;
  display: flex;
  gap: 1em;
  margin-top: 1em;
}

.tag {
  display: flex;
  align-items: center;
  gap: 0.5em;
  background: rgba(255, 255, 255, 0.1);
  padding: 0.5em;
  border-radius: 2em;
}

.tag p {
  font-size: 15px;
}

.search-items-container p {
  padding: 1em;
  font-size: 13.5px;
  color: var(--color-gray);
}

.search-items-container p span {
  color: #fff;
}

#search-items {
  list-style-type: none;
  padding: 0;
  margin: 0;
}

#search-items li {
  position: relative;
  padding: 1em;
  display: flex;
  cursor: pointer;
}

.item-icons {
  position: absolute;
  right: 1em;
  display: flex;
  gap: 0.75em;
}

.user {
  position: relative;
  top: -0.075em;
  width: 24px;
  height: 24px;
  background: var(--color-gray);
  border-radius: 100%;
  margin-right: 0.5em;
}

#search-items li a {
  position: relative;
  top: 0.25em;
  text-decoration: none;
  font-size: 15px;
  color: #fff;
}

li a span {
  color: var(--color-gray);
  padding-left: 0.25em;
}

#search-items li:hover:not(.header),
.f-item:hover {
  background-color: rgba(255, 255, 255, 0.05);
}

li:nth-child(1) .user {
  background: url("./user-1.jpg") no-repeat 50% 50%;
  background-size: cover;
}

li:nth-child(2) .user {
  background: url("./user-2.jpg") no-repeat 50% 50%;
  background-size: cover;
}

li:nth-child(3) .user {
  border-radius: 0;
  background: url("./user-3.jpg") no-repeat 50% 50%;
  background-size: cover;
}

.cmd-icon img {
  width: 45px;
  height: auto;
}

.quick-actions {
  width: 100%;
}

.q-action {
  padding: 0.75em 1em;
}

.q-action:nth-child(1) span {
  font-size: 13.5px;
  color: var(--color-gray);
}

.q-action {
  position: relative;
  display: flex;
}

.q-action:hover:not(.q-header) {
  background-color: rgba(255, 255, 255, 0.05);
}

.key {
  position: absolute;
  right: 1em;
}

.action {
  padding-left: 0.75em;
  cursor: pointer;
}

.action p {
  position: relative;
  top: 0.5em;
  line-height: 100%;
  font-size: 15px;
}

.q-action .icon,
.key,
.f-item .icon {
  width: 30px;
  height: 30px;
  background: rgba(255, 255, 255, 0.1);
  display: flex;
  justify-content: center;
  align-items: center;
  border-radius: 0.2em;
}

.q-action .icon i,
.f-item .icon i,
.key {
  color: #fff;
  font-size: 15px;
}

.f-header {
  padding: 1em;
  color: var(--color-gray);
  font-size: 13.5px;
}

.f-header p span {
  color: #fff;
}

.f-item {
  position: relative;
  width: 100%;
  display: flex;
  padding: 1em;
}

.file-item {
  display: flex;
  align-items: center;
  padding-left: 1em;
  gap: 0.75em;
}

.file-item p span {
  color: var(--color-gray);
}

.btn {
  position: absolute;
  right: 1em;
  display: flex;
  align-items: center;
  gap: 0.5em;
  color: var(--color-gray);
}

.file-item i {
  color: #69ca1f;
}

@media (max-width: 900px) {
  .search-modal {
    width: 90%;
  }
}
